    /**
     * Validates that a URL belongs to an allowed domain.
     */
    private boolean isAllowedUrl(String url) {
        if (url == null) return false;
        try {
            Uri uri = Uri.parse(url);
            String host = uri.getHost();
            String scheme = uri.getScheme();

            // Only allow HTTPS
            if (!"https".equalsIgnoreCase(scheme)) {
                Log.w(TAG, "Blocked non-HTTPS URL: " + url);
                return false;
            }

            if (host == null) return false;

            // Check against allowed domains
            for (String domain : ALLOWED_DOMAINS) {
                if (host.equalsIgnoreCase(domain)) {
                    return true;
                }
            }

            Log.w(TAG, "Blocked URL from unauthorized domain: " + host);
            return false;
        } catch (Exception e) {
            Log.e(TAG, "Error parsing URL: " + url, e);
            return false;
        }
    }

    /**
     * Secure WebViewClient that validates URLs and handles SSL properly.
     */
    private class SecureWebViewClient extends WebViewClient {

        @Override
        public boolean shouldOverrideUrlLoading(WebView view, WebResourceRequest request) {
            String url = request.getUrl().toString();

            if (isAllowedUrl(url)) {
                return false; // Let WebView handle it
            }

            // For external links, open in browser
            try {
                Intent intent = new Intent(Intent.ACTION_VIEW, Uri.parse(url));
                if (intent.resolveActivity(getPackageManager()) != null) {
                    startActivity(intent);
                }
            } catch (Exception e) {
                Log.e(TAG, "Cannot open external URL", e);
            }
            return true;
        }

        @Override
        public void onPageStarted(WebView view, String url, Bitmap favicon) {
            super.onPageStarted(view, url, favicon);
            Log.d(TAG, "Page loading: " + url);
        }

        @Override
        public void onPageFinished(WebView view, String url) {
            super.onPageFinished(view, url);
            Log.d(TAG, "Page loaded: " + url);
        }

        @Override
        public void onReceivedError(WebView view, WebResourceRequest request, WebResourceError error) {
            super.onReceivedError(view, request, error);
            if (request.isForMainFrame()) {
                Log.e(TAG, "Page load error: " + error.getDescription());
                loadErrorPage(view);
            }
        }

        @Override
        public void onReceivedHttpError(WebView view, WebResourceRequest request, WebResourceResponse errorResponse) {
            super.onReceivedHttpError(view, request, errorResponse);
            if (request.isForMainFrame()) {
                Log.e(TAG, "HTTP error: " + errorResponse.getStatusCode());
            }
        }

        @Override
        public void onReceivedSslError(WebView view, SslErrorHandler handler, SslError error) {
            // NEVER call handler.proceed() in production - always cancel on SSL errors
            Log.e(TAG, "SSL Error: " + error.toString());
            handler.cancel();

            runOnUiThread(() -> {
                new AlertDialog.Builder(WebViewActivity.this)
                        .setTitle("Security Error")
                        .setMessage("A secure connection could not be established. Please check your network connection.")
                        .setPositiveButton("OK", (dialog, which) -> {
                            if (view.canGoBack()) {
                                view.goBack();
                            }
                        })
                        .setCancelable(false)
                        .show();
            });
        }

        @Nullable
        @Override
        public WebResourceResponse shouldInterceptRequest(WebView view, WebResourceRequest request) {
            String url = request.getUrl().toString();
            
            // Block requests to non-allowed domains
            if (!isAllowedUrl(url)) {
                Log.w(TAG, "Intercepted request to unauthorized domain: " + url);
                return new WebResourceResponse("text/plain", "UTF-8", null);
            }
            
            return super.shouldInterceptRequest(view, request);
        }

        private void loadErrorPage(WebView view) {
            String errorHtml = "<html><body style='text-align:center;padding:50px;font-family:sans-serif;'>"
                    + "<h2>Unable to load page</h2>"
                    + "<p>Please check your internet connection and try again.</p>"
                    + "<button onclick='window.location.reload()' style='padding:10px 20px;font-size:16px;'>Retry</button>"
                    + "</body></html>";
            view.loadData(errorHtml, "text/html", "UTF-8");
        }
    }

