    /**
     * JavaScript Bridge - exposes native functionality to web content.
     * All methods validate input and check permissions before executing.
     */
    public static class NativeBridge {

        private final WebViewActivity activity;

        NativeBridge(WebViewActivity activity) {
            this.activity = activity;
        }

        /**
         * Get device information for analytics.
         * Returns sanitized device info as JSON string.
         */
        @JavascriptInterface
        public String getDeviceInfo() {
            try {
                JSONObject info = new JSONObject();
                info.put("platform", "android");
                info.put("sdkVersion", android.os.Build.VERSION.SDK_INT);
                info.put("appVersion", getAppVersion());
                return info.toString();
            } catch (JSONException e) {
                Log.e(TAG, "Error creating device info", e);
                return "{}";
            }
        }

        /**
         * Request location with user permission.
         * The result is delivered via a callback to JavaScript.
         */
        @JavascriptInterface
        public void requestLocation(String callbackName) {
            if (callbackName == null || !isValidCallbackName(callbackName)) {
                Log.w(TAG, "Invalid callback name for location request");
                return;
            }

            final String safeCallback = sanitizeCallbackName(callbackName);

            activity.runOnUiThread(() -> {
                if (activity.hasLocationPermission()) {
                    activity.fetchLocation(safeCallback);
                } else {
                    // Store callback for after permission is granted
                    activity.pendingLocationCallback = safeCallback;
                    ActivityCompat.requestPermissions(activity,
                            new String[]{
                                    Manifest.permission.ACCESS_FINE_LOCATION,
                                    Manifest.permission.ACCESS_COARSE_LOCATION
                            },
                            PERMISSION_REQUEST_LOCATION);
                }
            });
        }

        /**
         * Request camera capture.
         * Opens camera and returns photo URI via callback.
         */
        @JavascriptInterface
        public void requestCamera(String callbackName) {
            if (callbackName == null || !isValidCallbackName(callbackName)) {
                Log.w(TAG, "Invalid callback name for camera request");
                return;
            }

            final String safeCallback = sanitizeCallbackName(callbackName);

            activity.runOnUiThread(() -> {
                if (activity.hasCameraPermission()) {
                    activity.openCamera(safeCallback);
                } else {
                    activity.pendingCameraCallback = safeCallback;
                    ActivityCompat.requestPermissions(activity,
                            new String[]{Manifest.permission.CAMERA},
                            PERMISSION_REQUEST_CAMERA);
                }
            });
        }

        /**
         * Initiate a payment flow.
         * Validates payment data before processing.
         */
        @JavascriptInterface
        public void initiatePayment(String paymentDataJson, String callbackName) {
            if (callbackName == null || !isValidCallbackName(callbackName)) {
                Log.w(TAG, "Invalid callback name for payment");
                return;
            }

            final String safeCallback = sanitizeCallbackName(callbackName);

            if (paymentDataJson == null || paymentDataJson.isEmpty()) {
                activity.sendCallbackToJs(safeCallback, createErrorJson("Invalid payment data"));
                return;
            }

            try {
                JSONObject paymentData = new JSONObject(paymentDataJson);

                // Validate required fields
                if (!paymentData.has("amount") || !paymentData.has("currency") || !paymentData.has("orderId")) {
                    activity.sendCallbackToJs(safeCallback, createErrorJson("Missing required payment fields"));
                    return;
                }

                double amount = paymentData.getDouble("amount");
                String currency = paymentData.getString("currency");
                String orderId = paymentData.getString("orderId");

                // Validate amount
                if (amount <= 0 || amount > 999999.99) {
                    activity.sendCallbackToJs(safeCallback, createErrorJson("Invalid payment amount"));
                    return;
                }

                // Validate currency (ISO 4217)
                if (!isValidCurrency(currency)) {
                    activity.sendCallbackToJs(safeCallback, createErrorJson("Invalid currency code"));
                    return;
                }

                // Validate orderId format
                if (!isValidOrderId(orderId)) {
                    activity.sendCallbackToJs(safeCallback, createErrorJson("Invalid order ID"));
                    return;
                }

                activity.runOnUiThread(() -> activity.processPayment(amount, currency, orderId, safeCallback));

            } catch (JSONException e) {
                Log.e(TAG, "Invalid payment JSON", e);
                activity.sendCallbackToJs(safeCallback, createErrorJson("Invalid payment data format"));
            }
        }

        /**
         * Show a native toast message.
         */
        @JavascriptInterface
        public void showToast(String message) {
            if (message == null) return;
            // Limit message length
            final String safeMessage = message.length() > 200 ? message.substring(0, 200) : message;
            activity.runOnUiThread(() -> Toast.makeText(activity, safeMessage, Toast.LENGTH_SHORT).show());
        }

        /**
         * Share content using native share sheet.
         */
        @JavascriptInterface
        public void shareContent(String title, String text, String url) {
            if (text == null && url == null) return;

            // Validate URL if provided
            if (url != null && !url.isEmpty()) {
                Uri uri = Uri.parse(url);
                if (!"https".equalsIgnoreCase(uri.getScheme())) {
                    Log.w(TAG, "Share blocked: non-HTTPS URL");
                    return;
                }
            }

            activity.runOnUiThread(() -> {
                Intent shareIntent = new Intent(Intent.ACTION_SEND);
                shareIntent.setType("text/plain");
                if (title != null) {
                    String safeTitle = title.length() > 200 ? title.substring(0, 200) : title;
                    shareIntent.putExtra(Intent.EXTRA_SUBJECT, safeTitle);
                }
                StringBuilder content = new StringBuilder();
                if (text != null) {
                    String safeText = text.length() > 1000 ? text.substring(0, 1000) : text;
                    content.append(safeText);
                }
                if (url != null && !url.isEmpty()) {
                    if (content.length() > 0) content.append("\n");
                    content.append(url);
                }
                shareIntent.putExtra(Intent.EXTRA_TEXT, content.toString());
                activity.startActivity(Intent.createChooser(shareIntent, "Share via"));
            });
        }

        /**
         * Check if a specific permission is granted.
         */
        @JavascriptInterface
        public boolean hasPermission(String permissionType) {
            if (permissionType == null) return false;
            switch (permissionType.toLowerCase(Locale.ROOT)) {
                case "camera":
                    return activity.hasCameraPermission();
                case "location":
                    return activity.hasLocationPermission();
                default:
                    return false;
            }
        }

        // --- Validation helpers ---

        private boolean isValidCallbackName(String name) {
            // Only allow alphanumeric, dots, and underscores for callback names
            // This prevents JavaScript injection through callback names
            return name != null && name.matches("^[a-zA-Z_$][a-zA-Z0-9_$.]*$") && name.length() <= 100;
        }

        private String sanitizeCallbackName(String name) {
            // Additional sanitization
            return name.replaceAll("[^a-zA-Z0-9_$.]", "");
        }

        private boolean isValidCurrency(String currency) {
            if (currency == null || currency.length() != 3) return false;
            return currency.matches("^[A-Z]{3}$");
        }

        private boolean isValidOrderId(String orderId) {
            if (orderId == null || orderId.isEmpty() || orderId.length() > 64) return false;
            return orderId.matches("^[a-zA-Z0-9_-]+$");
        }

        private String createErrorJson(String message) {
            try {
                JSONObject error = new JSONObject();
                error.put("success", false);
                error.put("error", message);
                return error.toString();
            } catch (JSONException e) {
                return "{\"success\":false,\"error\":\"Unknown error\"}";
            }
        }

        private String getAppVersion() {
            try {
                return activity.getPackageManager()
                        .getPackageInfo(activity.getPackageName(), 0).versionName;
            } catch (PackageManager.NameNotFoundException e) {
                return "unknown";
            }
        }
    }

    // --- Permission and feature handling ---

    private String pendingLocationCallback;
    private String pendingCameraCallback;

    private boolean hasLocationPermission() {
        return ContextCompat.checkSelfPermission(this, Manifest.permission.ACCESS_FINE_LOCATION)
                == PackageManager.PERMISSION_GRANTED
                || ContextCompat.checkSelfPermission(this, Manifest.permission.ACCESS_COARSE_LOCATION)
                == PackageManager.PERMISSION_GRANTED;
    }

    private boolean hasCameraPermission() {
        return ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA)
                == PackageManager.PERMISSION_GRANTED;
    }

    @SuppressLint("MissingPermission")
    private void fetchLocation(String callbackName) {
        if (!hasLocationPermission()) {
            sendCallbackToJs(callbackName, "{\"success\":false,\"error\":\"Location permission denied\"}");
            return;
        }

        CancellationTokenSource cancellationTokenSource = new CancellationTokenSource();
        fusedLocationClient.getCurrentLocation(Priority.PRIORITY_BALANCED_POWER_ACCURACY,
                        cancellationTokenSource.getToken())
                .addOnSuccessListener(this, location -> {
                    if (location != null) {
                        try {
                            JSONObject result = new JSONObject();
                            result.put("success", true);
                            result.put("latitude", location.getLatitude());
                            result.put("longitude", location.getLongitude());
                            result.put("accuracy", location.getAccuracy());
                            result.put("timestamp", location.getTime());
                            sendCallbackToJs(callbackName, result.toString());
                        } catch (JSONException e) {
                            sendCallbackToJs(callbackName, "{\"success\":false,\"error\":\"Error formatting location\"}");
                        }
                    } else {
                        sendCallbackToJs(callbackName, "{\"success\":false,\"error\":\"Location unavailable\"}");
                    }
                })
                .addOnFailureListener(this, e -> {
                    Log.e(TAG, "Location fetch failed", e);
                    sendCallbackToJs(callbackName, "{\"success\":false,\"error\":\"Location fetch failed\"}");
                });
    }

    private void openCamera(String callbackName) {
        pendingCameraCallback = callbackName;
        Intent cameraIntent = createCameraIntent();
        if (cameraIntent != null) {
            try {
                startActivityForResult(cameraIntent, CAMERA_CAPTURE_REQUEST);
            } catch (Exception e) {
                Log.e(TAG, "Cannot open camera", e);
                sendCallbackToJs(callbackName, "{\"success\":false,\"error\":\"Cannot open camera\"}");
                pendingCameraCallback = null;
            }
        } else {
            sendCallbackToJs(callbackName, "{\"success\":false,\"error\":\"Cannot create camera intent\"}");
            pendingCameraCallback = null;
        }
    }

    @Nullable
    private Intent createCameraIntent() {
        Intent takePictureIntent = new Intent(MediaStore.ACTION_IMAGE_CAPTURE);
        if (takePictureIntent.resolveActivity(getPackageManager()) != null) {
            File photoFile = null;
            try {
                photoFile = createImageFile();
            } catch (IOException e) {
                Log.e(TAG, "Error creating image file", e);
            }

            if (photoFile != null) {
                Uri photoUri = FileProvider.getUriForFile(this,
                        getApplicationContext().getPackageName() + ".fileprovider",
                        photoFile);
                cameraPhotoPath = photoFile.getAbsolutePath();
                takePictureIntent.putExtra(MediaStore.EXTRA_OUTPUT, photoUri);
                takePictureIntent.addFlags(Intent.FLAG_GRANT_WRITE_URI_PERMISSION);
                return takePictureIntent;
            }
        }
        return null;
    }

    private File createImageFile() throws IOException {
        String timeStamp = new SimpleDateFormat("yyyyMMdd_HHmmss", Locale.US).format(new Date());
        String imageFileName = "IMG_" + timeStamp + "_";
        File storageDir = getExternalFilesDir(Environment.DIRECTORY_PICTURES);
        return File.createTempFile(imageFileName, ".jpg", storageDir);
    }

